    int n, e;
    scanf("%d %d", &n, &e);
    int groups = 0;
    int small = n < e ? n : e;
    int big = n > e ? n : e;
    for (int i = 0; i < big; i++) {
        if (big >= 2 && small >= 1) {
            groups += 1;
            big -= 2;
            small -= 1;
        } else if (big >= 1 && small >= 2) {
            groups += 1;
            big -= 1;
            small -= 2;
        } else {
            break;
        }
        int a = small;
        int b = big;
        small = a < b ? a : b;
        big = a > b ? a : b;
    }
    printf("%d\n", groups);
    return 0;
}
